# Öz metaclass-ın yaradılması
class MyMeta(type):
    def __new__(cls, name, bases, attrs):
        attrs['custom_attr'] = 'Mənim xüsusi atributum'
        return super().__new__(cls, name, bases, attrs)

class MyClass(metaclass=MyMeta):
    pass

obj = MyClass()
print(obj.custom_attr)

# __new__ və __init__ ilə metaclass
class MyMeta(type):
    def __new__(cls, name, bases, attrs):
        print(f'{name} sinifi yaradılır')
        return super().__new__(cls, name, bases, attrs)

    def __init__(cls, name, bases, attrs):
        print(f'{name} sinifi başlatılır')
        super().__init__(name, bases, attrs)

class MyClass(metaclass=MyMeta):
    pass

# Adi sinif və metaclass müqayisəsi
class RegularClass:
    x = 1

class MetaClass(type):
    def __new__(cls, name, bases, attrs):
        attrs['x'] = 100
        return super().__new__(cls, name, bases, attrs)

class CustomClass(metaclass=MetaClass):
    pass

print(RegularClass().x)
print(CustomClass().x)

