# Səhvlərdən qaçınma
class SafeMeta(type):
    def __new__(cls, name, bases, attrs):
        try:
            print(f'{name} sinifi yaradılır')
            return super().__new__(cls, name, bases, attrs)
        except Exception as e:
            print(f'Xəta: {e}')
            raise

class MyClass(metaclass=SafeMeta):
    pass

