import sys

class MyMeta(type):
    def __new__(cls, name, bases, attrs):
        return super().__new__(cls, name, bases, attrs)

class MyClass(metaclass=MyMeta):
    pass

print(f'MyClass ölçüsü: {sys.getsizeof(MyClass)} bayt')

# Sadə ORM metaclass
class ModelMeta(type):
    def __new__(cls, name, bases, attrs):
        attrs['fields'] = {k: v for k, v in attrs.items() if not k.startswith('__')}
        return super().__new__(cls, name, bases, attrs)

class User(metaclass=ModelMeta):
    username = str
    email = str

print(User.fields)

